def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math
    import re

    evidence_all = getattr(ctx, "evidence", {}) or {}
    feedback = str(
        getattr(ctx, "last_feedback", "")
        or evidence_all.get("__last_feedback__", "")
        or ""
    )

    DEG5 = math.radians(5.0)
    REV_STEP = math.radians(10.0)
    PRI_STEP = 0.010

    def _norm(v):
        n = math.sqrt(sum(float(x) * float(x) for x in v))
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [float(x) / n for x in v]

    def _rotate_toward(cur, tgt, max_angle):
        cur = _norm(cur)
        tgt = _norm(tgt)
        dot = max(-1.0, min(1.0, sum(cur[i] * tgt[i] for i in range(3))))
        ang = math.acos(dot)
        if ang <= 1e-12:
            return cur
        if ang <= max_angle:
            return tgt
        s = math.sin(ang)
        if abs(s) <= 1e-12:
            return cur
        t = max_angle / ang
        s0 = math.sin((1.0 - t) * ang) / s
        s1 = math.sin(t * ang) / s
        return _norm([s0 * cur[i] + s1 * tgt[i] for i in range(3)])

    def _initial(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        init = ev.get("initial_estimate") or {}
        axis = init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))
        return (
            _norm(axis),
            float(init.get("lower", 0.0)),
            float(init.get("upper", 0.0)),
        )

    def _target_axis(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return _norm(rec)

        cands = ev.get("axis_candidates") or []
        if cands:
            labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))
            best = None
            best_score = -1e100
            for c in cands:
                aw = c.get("axis_world")
                if not aw or len(aw) < 3:
                    continue
                score = float(c.get("score", 0.0) or 0.0)
                reason = str(c.get("reason") or "").lower()
                if joint.get("type") == "prismatic" and any(
                    k in labels for k in ("drawer", "pan", "tray", "basket", "bin")
                ):
                    if "outward" in reason:
                        score += 0.25
                    if "authored" in reason:
                        score -= 0.05
                if score > best_score:
                    best_score = score
                    best = aw
            if best is not None:
                return _norm(best)

        return _norm(joint.get("axis_world", [1.0, 0.0, 0.0]))

    def _feedback_has_negative_invalid(joint_name):
        return joint_name in feedback and (
            "invalid at q=-" in feedback
            or re.search(r"invalid\s+at\s+q\s*=\s*-", feedback)
        )

    def _apply_need_fix_action(joint_name, joint, axis, lower, upper, labels, target):
        axis = _rotate_toward(axis, target, DEG5)
        joint_type = joint.get("type")

        if joint_type == "revolute":
            if _feedback_has_negative_invalid(joint_name):
                lower = lower + REV_STEP
            elif "temperature" in labels or "temp" in labels:
                upper = upper + REV_STEP
            elif "timer" in labels:
                if lower < 0.0:
                    lower = lower + REV_STEP
            elif "knob" in labels or "dial" in labels:
                upper = upper + REV_STEP

        elif joint_type == "prismatic":
            if any(
                k in labels
                for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")
            ):
                upper = upper + PRI_STEP

        return axis, lower, upper

    def _reconstruct_previous_output(joint_name, joint, axis0, lower0, upper0, labels, target, state):
        axis = axis0[:]
        lower = lower0
        upper = upper0

        if state == "need_fix":
            for _ in range(3):
                axis, lower, upper = _apply_need_fix_action(
                    joint_name, joint, axis, lower, upper, labels, target
                )

        return axis, lower, upper

    estimates = []

    for joint_name, joint in sorted((getattr(ctx, "joints", {}) or {}).items()):
        ev = evidence_all.get(joint_name, {}) or {}
        labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))

        axis0, lower0, upper0 = _initial(joint_name, joint)
        target = _target_axis(joint_name, joint)

        state = str(ev.get("joint_state") or "need_fix").lower()
        if state not in ("correct", "need_fix"):
            state = "need_fix"

        prev_axis, prev_lower, prev_upper = _reconstruct_previous_output(
            joint_name, joint, axis0, lower0, upper0, labels, target, state
        )

        axis = prev_axis[:]
        lower = prev_lower
        upper = prev_upper
        axis_reason = "kept axis unchanged from the previous estimate"
        range_reason = "kept limits unchanged from the previous estimate"

        if state == "need_fix":
            axis, lower, upper = _apply_need_fix_action(
                joint_name, joint, prev_axis, prev_lower, prev_upper, labels, target
            )
            axis_reason = (
                "need_fix: rotated the previous unit axis toward the recommended "
                "evidence axis by one continuous-axis action no greater than 5 degrees"
            )

            if joint.get("type") == "revolute":
                if _feedback_has_negative_invalid(joint_name):
                    range_reason = (
                        "need_fix: previous validation explicitly failed this joint at "
                        "negative q, so raised only the lower limit by one allowed +10 "
                        "degree step, expressed in radians"
                    )
                elif "temperature" in labels or "temp" in labels:
                    range_reason = (
                        "need_fix: no failure was reported for this temperature knob, "
                        "but it still needs positive rotational sweep, so increased only "
                        "the upper limit by one allowed +10 degree step in radians"
                    )
                elif "timer" in labels and prev_lower < 0.0:
                    range_reason = (
                        "need_fix: timer knob negative range remains excessive, so raised "
                        "only the lower limit by one allowed +10 degree step in radians"
                    )
                elif "knob" in labels or "dial" in labels:
                    range_reason = (
                        "need_fix: generic knob still needs more positive sweep, so "
                        "increased only the upper limit by one allowed +10 degree step "
                        "in radians"
                    )
            elif joint.get("type") == "prismatic":
                if any(
                    k in labels
                    for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")
                ):
                    range_reason = (
                        "need_fix: drawer/pan travel remains short, so increased only "
                        "the upper limit by one allowed +10 mm step, expressed as "
                        "0.010 meters"
                    )
        else:
            axis_reason = "correct: left the previous axis unchanged"
            range_reason = "correct: left the previous lower and upper limits unchanged"

        estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=lower,
                upper=upper,
                axis_world=axis,
                confidence=0.50 if state == "need_fix" else 0.72,
                reason=(
                    "State per joint: %s. Previous estimate reconstructed from the "
                    "installed editable code as axis=%s, lower=%s, upper=%s. Evidence "
                    "target axis=%s. Last feedback considered: %r. This iteration: %s; "
                    "%s. The joint independently either stayed unchanged or took one "
                    "bounded update: axis rotation <=5 degrees, lower changed at most "
                    "once by an allowed ladder step, and upper changed at most once by "
                    "an allowed ladder step."
                )
                % (state, prev_axis, prev_lower, prev_upper, target, feedback, axis_reason, range_reason),
            )
        )

    return estimates

