    def _mentions_joint(joint_name):
        return joint_name in feedback

    def _axis_failure(joint_name):
        if not _mentions_joint(joint_name):
            return False
        low = feedback.lower()
        return (
            "qc_joint_axis" in low
            or "joint axis validation failed" in low
            or "deviates from" in low
            or "switch axis" in low
            or "rotate toward" in low
        )

    def _overlap_failure(joint_name):
        if not _mentions_joint(joint_name):
            return False
        low = feedback.lower()
        return (
            "sampled_motion_overlap" in low
            or "intersects parent/static geometry" in low
            or "sampled articulation motion intersects" in low
        )

