            axis_reason = "correct: no blocking feedback for this joint, so the axis stayed unchanged"
            range_reason = "correct: no blocking feedback for this joint, so limits stayed unchanged"
            confidence = 0.76
        else:
            state = "need_fix"

            if blocking_axis or blocking_overlap:
                axis = target
                axis_reason = (
                    "need_fix: blocking feedback for this joint was authoritative, "
                    "so this iteration uses the allowed direct switch to the "
                    "SDK-provided recommended/candidate axis %s"
                ) % (target,)
            else:
                axis_reason = (
                    "need_fix: no new axis-specific blocking signal for this joint, "
                    "so the axis stayed unchanged this iteration"
                )

            if joint.get("type") == "revolute":
                if _negative_invalid(joint_name):
                    lower = prev_lower + REV_STEP
                    range_reason = (
                        "need_fix: feedback reported invalid negative q, so raised "
