                    upper = prev_upper + REV_STEP
                    range_reason = (
                        "need_fix: temperature knob still needs positive sweep while "
                        "axis is being corrected, so increased only upper by one "
                        "allowed +10 degree step, in radians"
                    )
                elif "knob" in labels or "dial" in labels:
                    upper = prev_upper + REV_STEP
                    range_reason = (
                        "need_fix: knob/dial remains under positive sweep, so "
                        "increased only upper by one allowed +10 degree step, in radians"
                    )
                else:
                    range_reason = (
                        "need_fix: no revolute limit-specific blocking signal was "
                        "present, so lower and upper stayed unchanged"
                    )

            elif joint.get("type") == "prismatic":
                if any(k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")):
                    if blocking_overlap:
                        upper = prev_upper + PRI_STEP
                        range_reason = (
                            "need_fix: sampled-motion overlap at the previous upper "
                            "endpoint is blocking; along with switching to the outward "
                            "recommended axis, increased only upper by one allowed "
                            "+10 mm step, expressed as 0.010 meters"
                        )
                    else:
                        upper = prev_upper + PRI_STEP
                        range_reason = (
                            "need_fix: drawer/pan travel remains short, so increased "
                            "only upper by one allowed +10 mm step, expressed as "
                            "0.010 meters"
                        )
                else:
                    range_reason = (
                        "need_fix: no prismatic limit-specific evidence was present, "
                        "so lower and upper stayed unchanged"
                    )

        estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=lower,
                upper=upper,
                axis_world=axis,
                confidence=confidence,
                reason=(
                    "State per joint: %s. Previous estimate inferred from the last "
                    "installed editable-code iteration as axis=%s, lower=%s, upper=%s. "
                    "Last compile/QC feedback considered: %r. This iteration: %s; %s. "
