def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math
    import re

    evidence_all = getattr(ctx, "evidence", {}) or {}
    feedback = str(
        getattr(ctx, "last_feedback", "")
        or evidence_all.get("__last_feedback__", "")
        or ""
    )
    feedback_l = feedback.lower()

    REV_STEP = math.radians(10.0)  # allowed revolute ladder step, expressed in radians
    PRI_STEP = 0.010               # allowed prismatic ladder step, 10 mm in meters

    def _norm(v):
        try:
            vals = [float(v[0]), float(v[1]), float(v[2])]
        except Exception:
            vals = [1.0, 0.0, 0.0]
        n = math.sqrt(sum(x * x for x in vals))
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [x / n for x in vals]

    def _initial(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        init = ev.get("initial_estimate") or {}
        return (
            _norm(init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))),
            float(init.get("lower", 0.0)),
            float(init.get("upper", 0.0)),
        )

    def _recommended_axis(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return _norm(rec)

        best = None
        best_score = -1.0e100
        labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))
        for c in ev.get("axis_candidates") or []:
            aw = c.get("axis_world")
            if not aw or len(aw) < 3:
                continue
            score = float(c.get("score", 0.0) or 0.0)
            reason = str(c.get("reason") or "").lower()
            if joint.get("type") == "prismatic" and any(
                k in labels for k in ("drawer", "pan", "tray", "basket", "bin")
            ):
                if "outward" in reason:
                    score += 0.25
                if "authored" in reason:
                    score -= 0.05
            if score > best_score:
                best_score = score
                best = aw

        return _norm(best if best is not None else joint.get("axis_world", [1.0, 0.0, 0.0]))

    def _mentions(joint_name):
        return joint_name.lower() in feedback_l

    def _axis_blocked(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "qc_joint_axis" in feedback_l
            or "joint axis validation failed" in feedback_l
            or "deviates from" in feedback_l
            or "switch axis" in feedback_l
            or "rotate toward" in feedback_l
        )

    def _overlap_blocked(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "qc_sampled_motion_overlap" in feedback_l
            or "sampled_motion_overlap" in feedback_l
            or "intersects parent/static geometry" in feedback_l
            or "sampled articulation motion intersects" in feedback_l
        )

    def _negative_invalid(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "invalid at q=-" in feedback_l
            or re.search(r"invalid\s+at\s+q\s*=\s*-", feedback_l) is not None
        )

    def _feedback_axis_for_joint(joint_name):
        # Parse phrases such as "part_00: candidate axis +Z deviates ..."
        m = re.search(
            re.escape(joint_name.lower()) + r".{0,120}?candidate\s+axis\s+([+-][xyz])",
            feedback_l,
            flags=re.DOTALL,
        )
        if not m:
            return None
        label = m.group(1).upper()
        table = {
            "+X": [1.0, 0.0, 0.0],
            "-X": [-1.0, 0.0, 0.0],
            "+Y": [0.0, 1.0, 0.0],
            "-Y": [0.0, -1.0, 0.0],
            "+Z": [0.0, 0.0, 1.0],
            "-Z": [0.0, 0.0, -1.0],
        }
        return table.get(label)

    def _feedback_q_for_joint(joint_name):
        # Parse phrases such as "part_02: ... at upper endpoint q=0.08"
        m = re.search(
            re.escape(joint_name.lower()) + r".{0,240}?q\s*=\s*([-+]?\d+(?:\.\d+)?)",
            feedback_l,
            flags=re.DOTALL,
        )
        if not m:
            return None
        try:
            return float(m.group(1))
        except Exception:
            return None

    estimates = []

    for joint_name, joint in sorted((getattr(ctx, "joints", {}) or {}).items()):
        ev = evidence_all.get(joint_name, {}) or {}
        labels = " ".join(str(x).lower() for x in (ev.get("labels") or []))
        joint_type = joint.get("type")

        init_axis, init_lower, init_upper = _initial(joint_name, joint)
        prev_axis = _feedback_axis_for_joint(joint_name) or init_axis[:]
        prev_lower = init_lower
        prev_upper = init_upper

        q_seen = _feedback_q_for_joint(joint_name)
        if q_seen is not None:
            if abs(q_seen - init_lower) < abs(q_seen - init_upper):
                prev_lower = q_seen
            else:
                prev_upper = q_seen

        state = str(ev.get("joint_state") or "need_fix").lower()
        if state not in ("correct", "need_fix"):
            state = "need_fix"

        blocking_axis = _axis_blocked(joint_name)
        blocking_overlap = _overlap_blocked(joint_name)
        blocking_negative = _negative_invalid(joint_name)

        axis = prev_axis[:]
        lower = prev_lower
        upper = prev_upper
        axis_reason = "axis stayed unchanged"
        limit_reason = "limits stayed unchanged"
        confidence = 0.56

        if state == "correct" and not (blocking_axis or blocking_overlap or blocking_negative):
            confidence = 0.76
            axis_reason = "correct: no blocking signal for this joint, so axis stayed unchanged"
            limit_reason = "correct: no blocking signal for this joint, so lower and upper stayed unchanged"
        else:
            state = "need_fix"

            if blocking_axis or blocking_overlap:
                axis = _recommended_axis(joint_name, joint)
                axis_reason = (
                    "need_fix: blocking feedback for this joint is authoritative; "
                    "used the allowed direct switch to the SDK recommended/candidate axis"
                )

            if joint_type == "revolute":
                if blocking_negative:
                    lower = prev_lower + REV_STEP
                    limit_reason = (
                        "need_fix: feedback reported invalid negative q; raised lower by "
                        "one allowed +10 degree step, expressed in radians"
                    )
                elif "timer" in labels and prev_lower < 0.0:
