def estimate_limits(ctx):
    """Return one bounded-action LimitEstimate per joint in ctx.joints."""
    import math
    import re

    evidence_all = getattr(ctx, "evidence", {}) or {}
    feedback = str(
        getattr(ctx, "last_feedback", "")
        or evidence_all.get("__last_feedback__", "")
        or ""
    )
    feedback_l = feedback.lower()

    action_space = evidence_all.get("__action_space__", {}) or {}
    rev_step_deg = 10.0
    pri_step_mm = 10.0
    try:
        rev_steps = action_space.get("revolute_limit_steps_degrees") or []
        if 10.0 in [float(x) for x in rev_steps]:
            rev_step_deg = 10.0
    except Exception:
        pass
    try:
        pri_steps = action_space.get("prismatic_limit_steps_mm") or []
        if 10.0 in [float(x) for x in pri_steps]:
            pri_step_mm = 10.0
    except Exception:
        pass

    REV_STEP = math.radians(rev_step_deg)
    PRI_STEP = pri_step_mm / 1000.0

    def _norm(v):
        try:
            vals = [float(v[0]), float(v[1]), float(v[2])]
        except Exception:
            vals = [1.0, 0.0, 0.0]
        n = math.sqrt(sum(x * x for x in vals))
        if n <= 1e-12:
            return [1.0, 0.0, 0.0]
        return [x / n for x in vals]

    def _initial(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        init = ev.get("initial_estimate") or {}
        return (
            _norm(init.get("axis_world", joint.get("axis_world", [1.0, 0.0, 0.0]))),
            float(init.get("lower", 0.0)),
            float(init.get("upper", 0.0)),
        )

    def _labels(joint_name):
        ev = evidence_all.get(joint_name, {}) or {}
        return " ".join(str(x).lower() for x in (ev.get("labels") or []))

    def _recommended_axis(joint_name, joint):
        ev = evidence_all.get(joint_name, {}) or {}
        rec = ev.get("recommended_axis_world")
        if rec and len(rec) >= 3:
            return _norm(rec)

        labels = _labels(joint_name)
        best = None
        best_score = -1.0e100
        for c in ev.get("axis_candidates") or []:
            aw = c.get("axis_world")
            if not aw or len(aw) < 3:
                continue
            score = float(c.get("score", 0.0) or 0.0)
            reason = str(c.get("reason") or "").lower()
            if joint.get("type") == "prismatic" and any(
                k in labels for k in ("drawer", "pan", "tray", "basket", "bin")
            ):
                if "outward" in reason or "centroid-outward" in reason:
                    score += 0.25
                if "authored" in reason:
                    score -= 0.05
            if score > best_score:
                best_score = score
                best = aw

        return _norm(best if best is not None else joint.get("axis_world", [1.0, 0.0, 0.0]))

    def _mentions(joint_name):
        return joint_name.lower() in feedback_l

    def _axis_blocked(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "qc_joint_axis" in feedback_l
            or "joint axis validation failed" in feedback_l
            or "deviates from" in feedback_l
            or "switch axis" in feedback_l
            or "rotate toward" in feedback_l
        )

    def _overlap_blocked(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "qc_sampled_motion_overlap" in feedback_l
            or "sampled_motion_overlap" in feedback_l
            or "intersects parent/static geometry" in feedback_l
            or "sampled articulation motion intersects" in feedback_l
        )

    def _negative_invalid(joint_name):
        if not _mentions(joint_name):
            return False
        return (
            "invalid at q=-" in feedback_l
            or re.search(r"invalid\s+at\s+q\s*=\s*-", feedback_l) is not None
        )

    def _rejection_delta(joint_name, field):
        # Example: "part_00: upper changed by -0.698132 rad; allowed ..."
        pat = (
            re.escape(joint_name.lower())
            + r"\s*:\s*.{0,120}?"
            + re.escape(field.lower())
            + r"\s+changed\s+by\s+([-+]?\d+(?:\.\d+)?(?:[eE][-+]?\d+)?)"
        )
        m = re.search(pat, feedback_l, flags=re.DOTALL)
        if not m:
            return None
        try:
            return float(m.group(1))
        except Exception:
            return None

    def _prior_attempt_from_policy(joint_name, joint):
        """Reconstruct the last attempted value produced by the previous editable policy."""
        labels = _labels(joint_name)
        init_axis, init_lower, init_upper = _initial(joint_name, joint)
        axis = _recommended_axis(joint_name, joint)
        lower = init_lower
        upper = init_upper

        if joint.get("type") == "revolute":
            if _negative_invalid(joint_name) or ("timer" in labels and lower < 0.0):
                lower = lower + REV_STEP
            elif (
                "temperature" in labels
                or "temp" in labels
                or "knob" in labels
                or "dial" in labels
            ):
                upper = upper + REV_STEP
        elif joint.get("type") == "prismatic":
            if _overlap_blocked(joint_name) or any(
                k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")
            ):
                upper = upper + PRI_STEP

        return axis, lower, upper

    estimates = []

    for joint_name, joint in sorted((getattr(ctx, "joints", {}) or {}).items()):
        ev = evidence_all.get(joint_name, {}) or {}
        labels = _labels(joint_name)
        joint_type = joint.get("type")

        init_axis, init_lower, init_upper = _initial(joint_name, joint)
        attempted_axis, attempted_lower, attempted_upper = _prior_attempt_from_policy(joint_name, joint)

        # If the last action was rejected for an over-large limit delta, infer the
        # last accepted endpoint as: attempted_value - rejected_delta.  This lets
        # the next output take exactly one bounded ladder step from the accepted state
        # instead of jumping back to the initial estimate.
        base_axis = attempted_axis[:]
        base_lower = attempted_lower
        base_upper = attempted_upper

        lower_delta = _rejection_delta(joint_name, "lower")
        upper_delta = _rejection_delta(joint_name, "upper")
        if lower_delta is not None:
            base_lower = attempted_lower - lower_delta
        if upper_delta is not None:
            base_upper = attempted_upper - upper_delta

        state = str(ev.get("joint_state") or "need_fix").lower()
        if state not in ("correct", "need_fix"):
            state = "need_fix"

        blocking_axis = _axis_blocked(joint_name)
        blocking_overlap = _overlap_blocked(joint_name)
        blocking_negative = _negative_invalid(joint_name)
        rejection_seen = lower_delta is not None or upper_delta is not None

        axis = base_axis[:]
        lower = base_lower
        upper = base_upper
        confidence = 0.58
        axis_reason = "axis stayed unchanged"
        limit_reason = "limits stayed unchanged"

        if state == "correct" and not (blocking_axis or blocking_overlap or blocking_negative or rejection_seen):
            confidence = 0.78
            axis_reason = "correct: no blocking signal for this joint, so axis stayed unchanged"
            limit_reason = "correct: no blocking signal for this joint, so limits stayed unchanged"
        else:
            state = "need_fix"

            # Direct switch to a provided SDK recommended/candidate axis is allowed.
            axis = _recommended_axis(joint_name, joint)
            axis_reason = (
                "need_fix: used the allowed direct switch/stay action to the SDK "
                "recommended or best candidate axis for this joint"
            )

            if joint_type == "revolute":
                if blocking_negative:
                    lower = base_lower + REV_STEP
                    limit_reason = (
                        "need_fix: blocking feedback reported invalid negative q; "
                        "raised lower by exactly one allowed +10 degree step in radians"
                    )
                elif "timer" in labels and base_lower < 0.0:
                    lower = base_lower + REV_STEP
                    limit_reason = (
                        "need_fix: timer knob lower endpoint remains overly negative; "
                        "raised lower by exactly one allowed +10 degree step in radians"
                    )
                elif (
                    "temperature" in labels
                    or "temp" in labels
                    or "knob" in labels
                    or "dial" in labels
                ):
                    upper = base_upper + REV_STEP
                    limit_reason = (
                        "need_fix: rotary control needs positive sweep; increased upper "
                        "by exactly one allowed +10 degree step in radians"
                    )
            elif joint_type == "prismatic":
                if blocking_overlap:
                    upper = base_upper + PRI_STEP
                    limit_reason = (
                        "need_fix: overlap feedback is blocking; adjusted upper by exactly "
                        "one allowed +10 mm step in meters"
                    )
                elif any(k in labels for k in ("pull-out", "pull out", "drawer", "pan", "tray", "basket", "bin")):
                    upper = base_upper + PRI_STEP
                    limit_reason = (
                        "need_fix: pull-out drawer/pan travel still needs extension; "
                        "increased upper by exactly one allowed +10 mm step in meters"
                    )

        estimates.append(
            LimitEstimate(
                joint_name=joint_name,
                lower=lower,
                upper=upper,
                axis_world=_norm(axis),
                confidence=confidence,
                reason=(
                    "State per joint: %s. Initial evidence was axis=%s, lower=%s, upper=%s. "
                    "Last attempted policy value inferred as lower=%s, upper=%s; rejection "
                    "deltas parsed as lower=%s, upper=%s, giving current accepted baseline "
                    "lower=%s, upper=%s. Blocking signals: axis=%s, overlap=%s, "
                    "negative_invalid=%s. This iteration: %s; %s. Bounded-action rule "
                    "respected independently: axis changed at most once by direct SDK "
                    "candidate/recommended switch or stayed unchanged, lower changed at most "
                    "once by an allowed ladder step, and upper changed at most once by an "
                    "allowed ladder step."
                )
                % (
                    state,
                    init_axis,
                    init_lower,
                    init_upper,
                    attempted_lower,
                    attempted_upper,
                    lower_delta,
                    upper_delta,
                    base_lower,
                    base_upper,
                    blocking_axis,
                    blocking_overlap,
                    blocking_negative,
                    axis_reason,
                    limit_reason,
                ),
            )
        )

    return estimates

