                upper += PRI_10
                limit_action = "extended upper once by +10 mm, expressed as +0.010 m, to address sampled-motion overlap"
                confidence = 0.68

        estimates.append(
            LimitEstimate(
                joint_name=name,
                axis_world=norm(axis),
                lower=lower,
                upper=upper,
                confidence=confidence,
                reason=(
                    "State per joint: %s. Blocking signals this iteration: axis=%s, "
                    "sampled_overlap=%s, negative_invalid=%s. Parsed failed endpoints: "
                    "lower=%s, upper=%s. Action: axis %s; limits %s. Non-blocking "
                    "joints are kept unchanged from the previous visual/QC candidate; "
                    "the only authoritative blocking feedback is fixed first. Bounded "
                    "action rule respected independently for this joint: axis at most "
                    "one SDK candidate/recommended switch or unchanged, lower at most "
                    "one allowed ladder step, upper at most one allowed ladder step."
                )
                % (
                    state,
                    b_axis,
                    b_overlap,
                    b_negative,
                    fb_lower,
                    fb_upper,
